-- Estaciones: una por cada petroglifo con coordenadas conocidas.
INSERT INTO estaciones (nombre, descripcion, latitud, longitud, petroglifo_id)
SELECT nombre, descripcion, latitud, longitud, id
FROM petroglifos WHERE latitud IS NOT NULL AND longitud IS NOT NULL;

-- Recorrido completo ordenado por código de roca.
INSERT INTO recorridos (nombre, descripcion, activo)
VALUES ('Recorrido Sitio 9', 'Las rocas grabadas del Sitio 9, Museo Piedra Pintada.', TRUE);

INSERT INTO recorrido_estaciones (recorrido_id, estacion_id, orden)
SELECT 1, e.id, ROW_NUMBER() OVER (ORDER BY e.id) FROM estaciones e;

